import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ChangeGangRankComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(userId: number, newRankPosition: number) {
        this._data = [userId, newRankPosition];
    }

    public getMessageArray(): any[] {
        console.log('Sending ChangeGangRankComposer with data:', this._data);
        return this._data;
    }

    public dispose(): void {}
}
